    private var dataItems: [String] = []
    private let activityIndicator = UIActivityIndicatorView(style: .large)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        title = "API Client Demo"
        view.backgroundColor = .systemBackground
        
        setupUI()
        setupNavigationBar()
        setupInitialCredentials()
    }
    
    private func setupUI() {
        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "Cell")
        
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        activityIndicator.hidesWhenStopped = true
        
        view.addSubview(tableView)
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    private func setupNavigationBar() {
        let apiButton = UIBarButtonItem(title: "API", style: .plain, target: self, action: #selector(fetchFromAPI))
        let legacyButton = UIBarButtonItem(title: "Legacy", style: .plain, target: self, action: #selector(fetchFromLegacy))
        let postButton = UIBarButtonItem(title: "Post", style: .plain, target: self, action: #selector(postToAPI))
        
        navigationItem.rightBarButtonItems = [apiButton, legacyButton, postButton]
    }
    
    private func setupInitialCredentials() {
        _ = KeychainManager.shared.saveToken("sample_api_token_12345", for: "api_token")
        _ = KeychainManager.shared.saveToken("admin", for: "legacy_username")
        _ = KeychainManager.shared.saveToken("legacy_password_123", for: "legacy_password")
    }
    
    @objc private func fetchFromAPI() {
        activityIndicator.startAnimating()
        dataItems.removeAll()
        tableView.reloadData()
        
        APIClient.shared.fetchDataFromAPI(endpoint: "/api/v1/data") { [weak self] result in
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                
                switch result {
                case .success(let data):
                    self?.handleSuccessResponse(data, source: "API")
                case .failure(let error):
                    self?.handleError(error, source: "API")
                }
            }
        }
    }
    
    @objc private func fetchFromLegacy() {
        activityIndicator.startAnimating()
        dataItems.removeAll()
        tableView.reloadData()
        
        APIClient.shared.fetchDataFromLegacy(endpoint: "/legacy/data") { [weak self] result in
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                
                switch result {
                case .success(let data):
                    self?.handleSuccessResponse(data, source: "Legacy")
                case .failure(let error):
                    self?.handleError(error, source: "Legacy")
                }
            }
        }
    }
    
    @objc private func postToAPI() {
        activityIndicator.startAnimating()
        
        let postData: [String: Any] = [
            "name": "Test Item",
            "value": 42,
            "timestamp": Date().timeIntervalSince1970
        ]
        
        APIClient.shared.postDataToAPI(endpoint: "/api/v1/items", data: postData) { [weak self] result in
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                
                switch result {
                case .success(let data):
                    self?.handleSuccessResponse(data, source: "API POST")
                case .failure(let error):
                    self?.handleError(error, source: "API POST")
                }
            }
        }
    }
    
    private func handleSuccessResponse(_ data: Data, source: String) {
        if let jsonString = String(data: data, encoding: .utf8) {
            dataItems.append("[\(source)] Success")
            dataItems.append("Response: \(jsonString)")
        } else {
            dataItems.append("[\(source)] Success - Binary data received")
        }
        tableView.reloadData()
    }
    
    private func handleError(_ error: Error, source: String) {
        dataItems.append("[\(source)] Error")
        dataItems.append(error.localizedDescription)
        
        if let apiError = error as? APIError {
            switch apiError {
            case .httpError(let statusCode):
                dataItems.append("HTTP Status: \(statusCode)")
            default:
                break
            }
        }
        
        tableView.reloadData()
        
        let alert = UIAlertController(title: "Error", message: error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension ViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return dataItems.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "Cell", for: indexPath)
        cell.textLabel?.text = dataItems[indexPath.row]
        cell.textLabel?.numberOfLines = 0
        cell.textLabel?.font = UIFont.systemFont(ofSize: 12)
        return cell
    }
}